/**
 * 평균 계산, 평균 편차 계산
 */
function calculateMeanAndDeviation(values) {
  // 평균 계산
  const mean = values.reduce((sum, value) => sum + value, 0) / values.length;
  // 편차 계산
  const deviations = values.map(value => Math.abs(value - mean));
  // 평균 편차 계산
  const meanDeviation = deviations.reduce((sum, deviation) => sum + deviation, 0) / deviations.length;
  return {
    mean,
    meanDeviation
  };
}

/** 
 * number 값이 없으면 0으로 return
*/
function numberValueOrDefault(value, value1 = 0) {
  return value == null || value == undefined || isNaN(value) ? value1 : value;
}

/** 
 * 범위안에 존재하는지 체크크
*/
function isInRange(range, rangeOut) {
  // 양수와 음수 범위 계산
  const lowerBound = Math.min(-Math.abs(rangeOut), Math.abs(rangeOut));
  const upperBound = Math.max(-Math.abs(rangeOut), Math.abs(rangeOut));

  // 범위 체크
  return range >= lowerBound && range <= upperBound;
}

/**
 * 문자열 배열을 파싱하여 동적으로 this 객체에 속성을 설정하는 함수
 */
function assignDynamicProperties(params, context) {
  params.forEach(param => {
    const [key, value] = param.split('=');
    if (key && value) {
      try {
        context[key.trim()] = eval(value);
      } catch (e) {
        console.error(`Error parsing value for ${key.trim()}: ${value}`, e);
      }
    }
  });
}

/**
 * Object 객체의 값을 null로 전환해서 return, 특정 제외변수 추가.
 */
function createObjectWithNullValues(obj, excludeKeys = []) {
  return Object.keys(obj).reduce((newObj, key) => {
    // 제외할 키는 값 유지
    if (excludeKeys.includes(key)) {
      newObj[key] = obj[key];
    } else {
      newObj[key] = null;
    }
    return newObj;
  }, {});
}

/**
 * Object 객체의 값을 제외하는 것만 빼고 return
 */
function createObjectWithCopyValues(obj1, obj2, excludeKeys = []) {
  return Object.keys(obj1).reduce((newObj, key) => {
    // 제외할 키는 값 유지
    if (excludeKeys.includes(key)) {
      newObj[key] = _.cloneDeep(obj1[key]);
    } else {
      newObj[key] = _.cloneDeep(obj2[key]);
    }
    return newObj;
  }, {});
}

/**
 * 공정코드로 다음 공정의 value-text 객체 배열 찾기
 */
function getNextProcessNamesFromCode(currentCode, processData = []) {
  const currentProcess = processData.find(process => process["value"] === currentCode);
  if (!currentProcess) {
    console.error("해당 공정코드를 찾을 수 없습니다.");
    return [];
  }

  // 다음 공정코드를 가져옴
  const nextCodes = currentProcess["다음공정"].includes(",") ? currentProcess["다음공정"].split(",").map(code => code.trim()) : [currentProcess["다음공정"]];

  // 다음 공정코드 배열로 공정명 찾기
  const valueTextArray = nextCodes.map(nextCode => {
    const nextProcess = processData.find(process => process["value"] === nextCode);
    return nextProcess ? {
      value: nextProcess["value"],
      text: nextProcess["text"]
    } : null;
  });

  // null 값을 제거하고 결과 반환
  return valueTextArray.filter(name => name !== null);
}

/**
 * 정수아니면 소수점 내가 원하는 자리수만큼.
 */
function formatNumber(num, digits = 2) {
  // 소수점이 있는지 확인
  if (num % 1 === 0) {
    return num;
  } else {
    return num.toFixed(digits);
  }
}

/**
 * URL 찾기
 */
function findMenu(data, prodCategory, sysResourceName) {
  let result = null;
  data.some(item => {
    const currentProdCategory = item.prodCategory?.toUpperCase();
    const currentSysResourceName = item.sysResourceName?.toUpperCase();
    if (currentProdCategory === prodCategory && currentSysResourceName === sysResourceName) {
      result = item;
      return true; // Stop iteration when a match is found
    }
    if (item.childSysResc && item.childSysResc.length > 0) {
      result = findMenu(item.childSysResc, prodCategory, sysResourceName);
      return result !== null; // Stop iteration if a match is found in childSysResc
    }
    return false;
  });
  return result;
}

/**
 * 숫자와 소수점 허용
 */
function validateTemperatureInput(value, target) {
  // 숫자와 소수점만 허용
  const filteredValue = value.replace(/[^0-9.]/g, '');
  // 소수점이 여러 번 입력되지 않도록 제한
  const dotIndex = filteredValue.indexOf('.');
  const finalValue = dotIndex !== -1 ? filteredValue.slice(0, dotIndex + 1) + filteredValue.slice(dotIndex + 1).replace(/\./g, '') : filteredValue;
  return finalValue;
}

/**
 * 숫자만 허용
 */
function validateTemperatureInput1(value, target) {
  // 숫자만 허용
  const filteredValue = value.replace(/[^0-9]/g, '');
  return filteredValue;
}
